// Input: city, state, categories
const body = $input.first().json.body;
const city = body.city || 'Fayetteville';
const state = body.state || 'NC';
const categories = (body.categories || 'tattoo shop,barbershop,hair salon,gym,restaurant,bar,real estate,insurance,lawyer,dentist').split(',').map(s => s.trim());

return [{
  json: {
    city,
    state,
    categories
  }
}];

// Create a task for each route
const routes = $input.all().map(item => item.json);
const input = $('Parse Input').first().json;

return routes.map(route => ({
  json: {
    city: input.city,
    state: input.state,
    categories: input.categories,
    route_id: route.id,
    route_number: route.route_number,
    zip_code: route.zip_code,
    homes_covered: route.homes_covered
  }
}));

// For each route, generate search queries
const route = $input.json;
const queries = route.categories.map(cat => `${cat} in ${route.zip_code}`);

return queries.map(q => ({
  json: {
    query: q,
    city: route.city,
    state: route.state,
    route_id: route.route_id,
    route_number: route.route_number,
    zip_code: route.zip_code
  }
}));

// Parse results, filter by zip, attach route_id
const results = $input.all();
const prospects = [];

for (const item of results) {
  const places = item.json.results || [];
  const routeInfo = item.json;

  for (const place of places) {
    if (!place.name) continue;

    const address = place.formatted_address || '';
    const zipMatch = address.match(/\b(\d{5})\b/);
    const zip = zipMatch ? zipMatch[1] : '';

    // Only include if in target zip
    if (zip && zip !== routeInfo.zip_code) continue;

    prospects.push({
      json: {
        business_name: place.name,
        address: address,
        phone: place.formatted_phone_number || '',
        website: place.website || '',
        google_rating: place.rating || null,
        review_count: place.user_ratings_total || 0,
        category: place.types ? place.types[0] : 'other',
        google_place_id: place.place_id,
        lat: place.geometry?.location?.lat,
        lng: place.geometry?.location?.lng,
        zip: zip,
        city: routeInfo.city,
        state: routeInfo.state,
        source: 'google_maps',
        route_id: routeInfo.route_id,
        route_number: routeInfo.route_number,
        zip_code: routeInfo.zip_code
      }
    });
  }
}

// Deduplicate
const seen = new Set();
const unique = prospects.filter(p => {
  const key = `${p.json.business_name}|${p.json.address}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return unique;

// Aggregate results by route
const allProspects = $('Parse & Filter').all();
const routeSummary = {};

allProspects.forEach(p => {
  const routeNum = p.json.route_number;
  const zip = p.json.zip_code;
  const key = `${routeNum}-${zip}`;

  if (!routeSummary[key]) {
    routeSummary[key] = {
      route_number: routeNum,
      zip_code: zip,
      count: 0
    };
  }
  routeSummary[key].count++;
});

const summary = Object.values(routeSummary);
const totalCount = allProspects.length;
const cityInfo = $('Parse Input').first().json;

return [{
  json: {
    success: true,
    city: cityInfo.city,
    state: cityInfo.state,
    total_prospects: totalCount,
    routes_scraped: summary.length,
    breakdown: summary,
    message: `Scraped ${totalCount} prospects across ${summary.length} routes in ${cityInfo.city}, ${cityInfo.state}`
  }
}];
